mapper.select:
select rating_id, resource_id, user_id, rating_score, create_by, create_time, update_by, update_time, remark
from sc_resource_rating
where resource_id = #{param1} and user_id = #{param2}

mapper.update:
update sc_resource_rating
set rating_score = #{ratingScore},
    update_by = #{updateBy},
    update_time = sysdate(),
    remark = #{remark}
where rating_id = #{ratingId}

mapper.select:
select ifnull(avg(rating_score), 0) as avgRating, count(1) as ratingCount
from sc_resource_rating
where resource_id = #{resourceId}
